const jobs = $input.first().json.jobs || [];
return jobs.map(job => ({
  json: {
    title: (job.title || '').trim(),
    company: (job.company_name || '').trim(),
    location: (job.candidate_required_location || '').trim() || null,
    remote_type: 'remote',
    apply_url: job.url,
    source: 'remotive',
    description: job.description ? (job.salary ? `${job.description} Salary: ${job.salary}` : job.description) : (job.salary ? `Salary: ${job.salary}` : null),
    posted_at: job.publication_date ? new Date(job.publication_date).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.data || [];
return jobs.map(job => ({
  json: {
    title: (job.title || '').trim(),
    company: (job.company_name || '').trim(),
    location: (job.location || '').trim() || null,
    remote_type: job.remote ? 'remote' : 'onsite',
    apply_url: job.url,
    source: 'arbeitnow',
    description: job.description || null,
    posted_at: job.created_at ? new Date(job.created_at * 1000).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

const out = [];
for (const item of $input.all()) {
  const results = item.json.results || [];
  for (const job of results) {
    const locationText = (job.locations || []).map(l => l.name).join(', ');
    const text = `${job.name || ''} ${locationText}`.toLowerCase();
    out.push({
      json: {
        title: (job.name || '').trim(),
        company: (job.company && job.company.name || '').trim(),
        location: locationText || null,
        remote_type: (text.includes('flexible') || text.includes('remote')) ? 'remote' : 'onsite',
        apply_url: job.refs && job.refs.landing_page,
        source: 'themuse',
        description: job.contents || null,
        posted_at: job.publication_date ? new Date(job.publication_date).toISOString() : null
      }
    });
  }
}
return out.filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.results || [];
return jobs.map(job => {
  const text = `${job.title || ''} ${job.description || ''}`.toLowerCase();
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.company && job.company.display_name || '').trim(),
      location: (job.location && job.location.display_name || '').trim() || null,
      remote_type: text.includes('remote') ? 'remote' : (text.includes('hybrid') ? 'hybrid' : 'onsite'),
      apply_url: job.redirect_url,
      source: 'adzuna',
      description: job.description || null,
      posted_at: job.created ? new Date(job.created).toISOString() : null,
      salary_min: job.salary_min || null,
      salary_max: job.salary_max || null,
      adzuna_contract_time: job.contract_time || null,
      adzuna_contract_type: job.contract_type || null
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.jobs || [];
return jobs.map(job => {
  const text = `${job.title || ''} ${job.snippet || ''}`.toLowerCase();
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.company || '').trim(),
