const arr = $input.first().json;
const jobs = Array.isArray(arr) ? arr.filter(j => j && j.id) : [];
return jobs.map(job => ({
  json: {
    title: (job.position || '').trim(),
    company: (job.company || '').trim(),
    location: (job.location || '').trim() || null,
    remote_type: 'remote',
    apply_url: job.url,
    source: 'remoteok',
    description: job.description || null,
    posted_at: job.date ? new Date(job.date).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

return $input.all().map(item => {
  const raw = item.json;
  const titleFull = raw.title || '';
  const splitIdx = titleFull.indexOf(':');
  const company = splitIdx > -1 ? titleFull.slice(0, splitIdx).trim() : null;
  const title = splitIdx > -1 ? titleFull.slice(splitIdx + 1).trim() : titleFull.trim();
  return {
    json: {
      title,
      company,
      location: raw.region || null,
      remote_type: 'remote',
      apply_url: raw.link,
      source: 'weworkremotely',
      description: raw.contentSnippet || raw.content || raw.summary || null,
      posted_at: raw.pubDate ? new Date(raw.pubDate).toISOString() : (raw.isoDate || null)
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.jobs || $input.first().json.data || [];
return jobs.map(job => {
  const location = Array.isArray(job.locationRestrictions) ? job.locationRestrictions.join(', ') : (job.locationRestrictions || null);
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.companyName || '').trim(),
      location: location || null,
      remote_type: 'remote',
      apply_url: job.applicationLink || job.guid || null,
      source: 'himalayas',
      description: job.description || job.excerpt || null,
      posted_at: job.pubDate ? new Date(typeof job.pubDate === 'number' ? job.pubDate * 1000 : job.pubDate).toISOString() : null
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

