function stripHtml(html) {
  if (!html) return null;
  return html
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#0?39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim() || null;
}

return $input.all().map(item => ({
  json: { ...item.json, description: stripHtml(item.json.description) }
}));

const inferEmploymentType = (title, description, adzunaContractTime, adzunaContractType) => {
  if (adzunaContractTime === 'part_time') return 'Part-time';
  if (adzunaContractType === 'contract') return 'Contract';
  const text = `${title || ''} ${description || ''}`.toLowerCase();
  if (/freelance/.test(text)) return 'Freelance';
  if (/part[\s-]?time/.test(text)) return 'Part-time';
  if (/\bcontract(or)?\b/.test(text)) return 'Contract';
  return 'Full-time';
};

const inferRemoteRegion = (locationText, remoteType) => {
  if (remoteType !== 'remote') return null;
  const loc = (locationText || '').toLowerCase();
  if (!loc) return null;
  if (/worldwide|anywhere|global/.test(loc)) return 'Worldwide';
  if (/\beu\b|european union/.test(loc)) return 'EU Only';
  if (/\buk\b|united kingdom|britain/.test(loc)) return 'UK/EU Only';
  if (/europe/.test(loc)) return 'Europe Only';
  const hasUS = /\busa?\b|united states/.test(loc);
  const hasCanada = /canada/.test(loc);
  if (hasUS && hasCanada) return 'US/Canada Only';
  if (hasUS) return 'US Only';
  if (/asia|apac/.test(loc)) return 'Asia-Pacific Only';
  if (/americas/.test(loc)) return 'Americas Only';
  return null;
};

const inferWorkplaceLocation = (locationText, remoteType) => {
  if (remoteType === 'remote') return { city: null, country: null };
  const parts = (locationText || '').split(',').map(s => s.trim()).filter(Boolean);
  return {
    city: parts[0] || null,
    country: parts.length > 1 ? parts[parts.length - 1] : null
  };
};

const inferCareerLevel = (title) => {
  const t = (title || '').toLowerCase();
  const levels = [];
  if (/\bintern(ship)?\b/.test(t)) levels.push('Internship');
  if (/entry[\s-]?level|no experience|\bgraduate\b|\btrainee\b/.test(t)) levels.push('EntryLevel');
  if (/\bjunior\b/.test(t)) levels.push('Junior');
  if (/\bassociate\b/.test(t)) levels.push('Associate');
  if (/mid[\s-]?level/.test(t)) levels.push('MidLevel');
  if (/senior director/.test(t)) levels.push('SeniorDirector');
  else if (/\bdirector\b/.test(t)) levels.push('Director');
  if (/senior manager/.test(t)) levels.push('SeniorManager');
  else if (/\bmanager\b/.test(t)) levels.push('Manager');
  if (/\bstaff\b/.test(t)) levels.push('Staff');
  if (/\bprincipal\b/.test(t)) levels.push('Principal');
  if (/\blead\b/.test(t)) levels.push('Lead');
  if (/\bsenior\b/.test(t) && !/senior (director|manager)/.test(t)) levels.push('Senior');
  if (/\bsvp\b|senior vice president/.test(t)) levels.push('SVP');
  else if (/\bevp\b|executive vice president/.test(t)) levels.push('EVP');
  else if (/\bvp\b|vice president/.test(t)) levels.push('VP');
  if (/chief (executive|technology|operating|financial) officer|\bcto\b|\bceo\b|\bcfo\b|\bcoo\b/.test(t)) levels.push('CLevel');
  if (/founder/.test(t)) levels.push('Founder');
  return levels.length ? Array.from(new Set(levels)) : ['NotSpecified'];
};

const CURRENCY_SYMBOLS = { '$': 'USD', '£': 'GBP', '€': 'EUR' };

const parseSalaryFromText = (text) => {
  const match = /([$£€])\s?([\d,]{3,7})(k)?(?:\s?(?:-|–|to)\s?[$£€]?\s?([\d,]{3,7})(k)?)?/i.exec(text || '');
  if (!match) return null;
  const currency = CURRENCY_SYMBOLS[match[1]] || 'USD';
  const toNumber = (raw, isK) => {
    const n = parseFloat(raw.replace(/,/g, ''));
    return isK ? n * 1000 : n;
  };
  const first = toNumber(match[2], !!match[3]);
  if (first < 1000 && !match[3]) return null;
  const second = match[4] ? toNumber(match[4], !!match[5]) : null;
  const min = second ? Math.min(first, second) : first;
  const max = second ? Math.max(first, second) : first;
  let unit = 'year';
  if (/\/\s?(hour|hr)\b|per hour/i.test(text)) unit = 'hour';
  else if (/\/\s?day\b|per day/i.test(text)) unit = 'day';
  else if (/\/\s?week\b|per week/i.test(text)) unit = 'week';
  else if (/\/\s?month\b|per month/i.test(text)) unit = 'month';
  return { min, max, currency, unit };
};

return $input.all().map(item => {
  const j = item.json;
  const type = inferEmploymentType(j.title, j.description, j.adzuna_contract_time, j.adzuna_contract_type);
  const remote_region = inferRemoteRegion(j.location, j.remote_type);
  const { city, country } = inferWorkplaceLocation(j.location, j.remote_type);
  const career_level = inferCareerLevel(j.title);

  let salary = null;
  if (j.source === 'adzuna' && (j.salary_min || j.salary_max)) {
    salary = { min: j.salary_min || null, max: j.salary_max || null, currency: 'GBP', unit: 'year' };
  } else {
    salary = parseSalaryFromText(`${j.title || ''} ${j.description || ''}`);
  }

  return {
    json: {
      ...j,
      type,
      remote_region,
      workplace_city: city,
      workplace_country: country,
      career_level,
      salary_min: salary ? salary.min : null,
      salary_max: salary ? salary.max : null,
      salary_currency: salary ? salary.currency : 'USD',
      salary_unit: salary ? salary.unit : 'year'
    }
  };
});

const includeKeywords = ['intern', 'graduate', 'junior', 'entry level', 'associate', '0-1 years', '0-2 years', 'no experience', 'trainee'];
const excludeKeywords = ['5+ years', 'senior only', 'unpaid', 'commission-only', 'commission only'];

const out = [];
for (const item of $input.all()) {
  const text = `${item.json.title || ''} ${item.json.description || ''}`.toLowerCase();

  const isExcluded = excludeKeywords.some(k => text.includes(k));
  if (isExcluded) continue;

  const entryLevel = includeKeywords.some(k => text.includes(k));
  out.push({ json: { ...item.json, entry_level: entryLevel } });
}
return out;

const suspiciousKeywords = [
  'pay to apply', 'training fee', 'registration fee', 'whatsapp only', 'whatsapp-only',
  'crypto', 'trading platform', 'forex', 'investment opportunity'
];

return $input.all().map(item => {
  const text = `${item.json.title || ''} ${item.json.description || ''}`.toLowerCase();
  const noCompanyName = !item.json.company || item.json.company.trim().length === 0;
  const keywordHit = suspiciousKeywords.some(k => text.includes(k));
  const unrealisticSalary = /\$\s?\d{4,}\s*\/\s*(day|hour)/i.test(text) || /earn\s+\$?\d{3,}[,\d]*\s+per\s+week/i.test(text);

  return {
    json: {
      ...item.json,
      flagged_suspicious: keywordHit || noCompanyName || unrealisticSalary
    }
  };
});

const hasSalaryMention = text => /\$|salary|per annum|per year|per month|\bpkr\b|\busd\b|k\/year/i.test(text);

return $input.all().map(item => {
  const j = item.json;
  const text = `${j.title || ''} ${j.description || ''}`;
  let score = 0;

  if (hasSalaryMention(text)) score += 20;

  if (j.posted_at) {
    const daysOld = (Date.parse(j.posted_at) ? (new Date() - new Date(j.posted_at)) / (1000 * 60 * 60 * 24) : 999);
    if (daysOld <= 7) score += 20;
  }

  if (j.remote_type === 'remote' || j.remote_type === 'hybrid') score += 15;
  if (j.entry_level) score += 15;
  if (j.apply_url) score += 10;

  if (j.flagged_suspicious) score -= 50;
  if (!hasSalaryMention(text) && !j.description) score -= 10;

  score = Math.max(0, Math.min(100, score));

  return { json: { ...j, score } };
});
